    kw_null: _ => token(prec(1, /[nN][uU][lL][lL]/)),
    kw_or: _ => token(prec(1, /[oO][rR]/)),
    kw_strict: _ => token(prec(1, /[sS][tT][rR][iI][cC][tT]/)),
