    kw_close: _ => token(prec(1, /[cC][lL][oO][sS][eE]/)),
    kw_collate: _ => token(prec(1, /[cC][oO][lL][lL][aA][tT][eE]/)),
    kw_column: _ => token(prec(1, /[cC][oO][lL][uU][mM][nN]/)),
    kw_column_name: _ => token(prec(1, /[cC][oO][lL][uU][mM][nN]_[nN][aA][mM][eE]/)),
