    kw_detail: _ => token(prec(1, /[dD][eE][tT][aA][iI][lL]/)),
    kw_diagnostics: _ => token(prec(1, /[dD][iI][aA][gG][nN][oO][sS][tT][iI][cC][sS]/)),
